import scala.collection.mutable.PriorityQueue

def solve(grid: Array[Array[Long]], k: Long): Long = {
  val m = grid.length
  val n = grid(0).length
  val dist = Array.ofDim[Long](m, n)
  val dirs = Array((0, 1), (1, 0)) // right, down

  // Initialize distance to start
  dist(0)(0) = grid(0)(0)

  // Use Dijkstra's algorithm with a priority queue
  val pq = PriorityQueue[(Long, Int, Int, Int)]((dist(0)(0), 0, 0, 0)) // (cost, row, col, numTransports)

  while (pq.nonEmpty) {
    val (cost, row, col, transports) = pq.dequeue()

    // If we've reached the end, return the cost
    if (row == m - 1 && col == n - 1) return cost

    // If we've used all transports, only move normally
    if (transports == k) {
      for ((dr, dc) <- dirs) {
        val newRow = row + dr
        val newCol = col + dc
        if (newRow < m && newCol < n) {
          val newCost = cost + grid(newRow)(newCol)
          if (newCost < dist(newRow)(newCol)) {
            dist(newRow)(newCol) = newCost
            pq.enqueue((newCost, newRow, newCol, transports))
          }
        }
      }
    } else {
      // Move normally
      for ((dr, dc) <- dirs) {
        val newRow = row + dr
        val newCol = col + dc
        if (newRow < m && newCol < n) {
          val newCost = cost + grid(newRow)(newCol)
          if (newCost < dist(newRow)(newCol)) {
            dist(newRow)(newCol) = newCost
            pq.enqueue((newCost, newRow, newCol, transports))
          }
        }
      }

      // Use teleportation
      for (i <- 0 until m) {
        for (j <- 0 until n) {
          if (grid(i)(j) <= grid(row)(col)) {
            val newCost = cost
            if (newCost < dist(i)(j)) {
