def grid(grid: Array[Array[Long]])(k: Long): Long = {
  val m = grid.length
  val n = grid(0).length
  val dist = Array.ofDim[Long](m, n)
  val pq = PriorityQueue[(Long, Int, Int, Int)]()

  dist(0)(0) = 0
  pq.enqueue((0, 0, 0, 0)) // (cost, row, col, usedTransports)

  val dirs = Array[(Int, Int)]((0, 1), (1, 0))

  while (pq.nonEmpty) {
    val (cost, row, col, used) = pq.dequeue()

    if (row == m - 1 && col == n - 1) return cost

    if (used >= k) {
      for ((dr, dc) <- dirs) {
        val r = row + dr
        val c = col + dc
        if (r < m && c < n) {
          val newCost = cost + grid(r)(c)
          if (newCost < dist(r)(c)) {
            dist(r)(c) = newCost
            pq.enqueue((newCost, r, c, used))
          }
        }
      }
    } else {
      // Regular move
      for ((dr, dc) <- dirs) {
        val r = row + dr
        val c = col + dc
        if (r < m && c < n) {
          val newCost = cost + grid(r)(c)
          if (newCost < dist(r)(c)) {
            dist(r)(c) = newCost
            pq.enqueue((newCost, r, c, used))
          }
        }
      }

      // Transport
      val currentVal = grid(row)(col)
      for (i <- 0 until m) {
        for (j <- 0 until n) {
          if (grid(i)(j) <= currentVal && (i != row || j != col)) {
            if (cost < dist(i)(j)) {
              dist(i)(j) = cost
              pq.enqueue((cost, i, j, used + 1))
            }
          }
        }
      }
    }
  }

  dist(m - 1)(n - 1)
}
